import React, { useState, useEffect, useRef } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import './styles/App.css';

// Theme context
import { ThemeProvider } from './contexts/ThemeContext';

// Import components
import Header from './components/Header/Header';
import Navigation from './components/Navigation/Navigation';
import Landing from './components/Landing/Landing';
import About from './components/About/About';
import Experience from './components/Experience/Experience';
import Skills from './components/Skills/Skills';
import Projects from './components/Projects/Projects';
import Contact from './components/Contact/Contact';
import Footer from './components/Footer/Footer';

// Import data service
import { fetchProfileData } from './services/DataService';

function App() {
  // State for profile data
  const [profileData, setProfileData] = useState(null);
  const [loading, setLoading] = useState(true);
  
  // Refs for section scrolling
  const sectionRefs = {
    home: useRef(null),
    about: useRef(null),
    experience: useRef(null),
    skills: useRef(null),
    projects: useRef(null),
    contact: useRef(null)
  };
  
  // Load profile data
  useEffect(() => {
    const loadProfileData = async () => {
      try {
        setLoading(true);
        const data = await fetchProfileData();
        setProfileData(data);
      } catch (error) {
        console.error('Error loading profile data:', error);
      } finally {
        setLoading(false);
      }
    };
    
    loadProfileData();
  }, []);
  
  // Handle navigation
  const handleNavigate = (sectionId) => {
    const sectionRef = sectionRefs[sectionId];
    if (sectionRef && sectionRef.current) {
      sectionRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  };
  
  // Create navigation items
  const navItems = [
    { id: 'home', label: 'Home' },
    { id: 'about', label: 'About' },
    { id: 'experience', label: 'Experience' },
    { id: 'skills', label: 'Skills' },
    { id: 'projects', label: 'Projects' },
    { id: 'contact', label: 'Contact' }
  ];

  return (
    <ThemeProvider>
      <Router>
        <div className="App">
          <Header profile={profileData} onNavigate={handleNavigate} />
          <Navigation navItems={navItems} onNavigate={handleNavigate} />
          
          <main className="App-main">
            <Routes>
              <Route path="/" element={
                <>
                  <section id="home" ref={sectionRefs.home}>
                    <Landing 
                      title={profileData?.name || "I'm John Doe"}
                      subtitle={profileData?.title || "Full Stack Developer"}
                      description={profileData?.shortBio || "I build beautiful, responsive web applications with modern technologies."}
                    />
                  </section>
                  
                  <section id="about" ref={sectionRefs.about}>
                    <About 
                      profileData={profileData}
                    />
                  </section>
                  
                  <section id="experience" ref={sectionRefs.experience}>
                    <Experience 
                      experiences={profileData?.experiences || []}
                    />
                  </section>
                  
                  <section id="skills" ref={sectionRefs.skills}>
                    <Skills 
                      skills={profileData?.skills || []}
                    />
                  </section>
                  
                  <section id="projects" ref={sectionRefs.projects}>
                    <Projects 
                      projects={profileData?.projects || []}
                    />
                  </section>
                  
                  <section id="contact" ref={sectionRefs.contact}>
                    <Contact 
                      contactInfo={profileData?.contact || {}}
                    />
                  </section>
                </>
              } />
              
              {/* Additional routes can be added here */}
              <Route path="/projects/:id" element={<Projects />} />
              <Route path="*" element={<div className="not-found">Page Not Found</div>} />
            </Routes>
          </main>
          
          <Footer 
            copyright={`© ${new Date().getFullYear()} ${profileData?.name || 'Portfolio'}. All rights reserved.`}
            socialLinks={profileData?.socialLinks || []}
          />
        </div>
      </Router>
    </ThemeProvider>
  );
}

export default App;
